const cheerio=require('cheerio');
const html=$input.first().json.body||'';
const pos=$input.first().json.position||0;
const url=$input.first().json.url||'';
const domain=$input.first().json.domain||'';
const title=$input.first().json.title||'';
const $c=cheerio.load(html);
$c('script,style,nav,footer,header,aside').remove();
const h={h1:[],h2:[],h3:[]};
$c('h1').each(function(){h.h1.push($c(this).text().trim());});
$c('h2').each(function(){h.h2.push($c(this).text().trim());});
$c('h3').each(function(){h.h3.push($c(this).text().trim());});
const text=$c('body').text().replace(/\s+/g,' ').trim();
const words=text.split(/[\s\u200C]+/).filter(w=>w.length>1);
const stops=new Set(['و','در','به','از','که','این','را','با','است','آن','یک','برای','تا','ها','های','می','شود','کرد','شده']);
const freq={};
(text.match(/[\u0600-\u06FF\u200C]+/g)||[]).forEach(w=>{const n=w.toLowerCase().replace(/\u200C{2,}/g,'\u200C');if(n.length>=3&&!stops.has(n))freq[n]=(freq[n]||0)+1;});
const topKw=Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,30).map(e=>e[0]);
return[{json:{position:pos,url,domain,title,word_count:words.length,h1_count:h.h1.length,h2_count:h.h2.length,h3_count:h.h3.length,images:$c('img').length,schema_types:'',top_keywords:topKw,headings:h}}];

const comps=$input.all().map(i=>i.json);
const meta=$node['Parse SERP'].json;
const n=comps.length||1;
const avgW=Math.round(comps.reduce((s,c)=>s+c.word_count,0)/n);
const avgH=Math.round(comps.reduce((s,c)=>s+c.h1_count+c.h2_count+c.h3_count,0)/n);
const kwC={};
comps.forEach(c=>(c.top_keywords||[]).forEach(k=>{kwC[k]=(kwC[k]||0)+1;}));
const lsi=Object.entries(kwC).filter(e=>e[1]>=3).sort((a,b)=>b[1]-a[1]).slice(0,30).map(e=>e[0]);
const h2T={};
comps.forEach(c=>(c.headings?.h2||[]).forEach(h=>{const n2=h.toLowerCase().trim();if(n2.length>5)h2T[n2]=(h2T[n2]||0)+1;}));
const gap=Object.entries(h2T).filter(e=>e[1]>=2).sort((a,b)=>b[1]-a[1]).slice(0,15).map(e=>e[0]);
return[{json:{analysis_id:meta.analysis_id,callback_url:meta.callback_url,avg_word_count:avgW,avg_headings:avgH,lsi_keywords:lsi,content_gap:gap,questions:meta.questions||[],competitors:comps}}];
